import re

with open('/tmp/qemu_trace.log', 'r') as f:
    content = f.read()

# Find all writes to any fd
all_writes = re.findall(r'write\(([0-9]+), "([^"]*)"(?:, (\d+))?\)', content)

fds = {}
for fd, text, _ in all_writes:
    if fd not in fds:
        fds[fd] = []
    text = text.replace('\\n', '\n').replace('\\t', '\t').replace('\\r', '')
    if not text.endswith('...'):
        fds[fd].append(text)

for fd in sorted(fds.keys()):
    output = ''.join(fds[fd])
    print(f"\n=== FD {fd} ===")
    if 'hello' in output:
        print("FOUND 'hello'")
        print(output[:200])
    else:
        print(f"Length: {len(output)}")
        if len(output) < 100:
            print(repr(output))
        else:
            print("Last 100 chars:", repr(output[-100:]))
EOF
